function countSwaps(arr) {
  const n = arr.length;
  let swapCount = 0;

  for (let i = 0; i < n - 1; i++) {
    for (let j = 0; j < n - i - 1; j++) {
      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
        swapCount++;
      }
    }
  }

  return swapCount;
}

