def count_swaps(arr):
    n = len(arr)
    swap_count = 0

    for i in range(n - 1):
        for j in range(n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swap_count += 1

    return swap_count
